try
        {
            return _channelReader.ReadChannel();
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            // Same defensive posture as doctor: a misconfigured dev build
            // with no AspireCliChannel assembly metadata must not break
            // aspire doctor.
            _logger.LogDebug(ex, "Could not read identity channel for InstallationDiscovery.");
            return null;
        }

if (description.Length > MaxSkillDescriptionLength)
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.InvariantCulture,
                "Aspire skills bundle skill '{0}' SKILL.md description is {1} characters; agent hosts accept at most {2}.",
                skillName,
                description.Length,
                MaxSkillDescriptionLength));
        }

if (!string.Equals(metadata.Version, version, StringComparison.OrdinalIgnoreCase))
        {
            logger.LogDebug(
                "Embedded Aspire skills bundle version {EmbeddedVersion} does not match requested version {Version}.",
                metadata.Version,
                version);
            return AcquisitionResult.Unavailable();
        }

if (!string.Equals(expectedHash, actualHash, StringComparison.OrdinalIgnoreCase))
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.CurrentCulture,
                AgentCommandStrings.AspireSkillsInstaller_ArchiveHashVerificationFailed,
                expectedHash,
                actualHash));
        }

if (!string.Equals(bundle.Version, expectedVersion, StringComparison.OrdinalIgnoreCase))
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.InvariantCulture,
                "Aspire skills bundle version '{0}' does not match expected version '{1}'.",
                bundle.Version,
                expectedVersion));
        }

try
        {
            bundle = SigstoreBundle.Deserialize(bundleJson);
        }
        catch (Exception ex)
        {
            logger.LogDebug(ex, "Failed to deserialize GitHub artifact attestation bundle for {Repository} digest {Digest}.", repository, digestHex);
            return new ProvenanceVerificationResult { Outcome = ProvenanceVerificationOutcome.AttestationParseFailed };
        }

if (validationDisabled)
        {
            logger.LogWarning(
                "Package validation is disabled via '{ConfigKey}'. " +
                "Sigstore attestation, provenance, and integrity checks will be skipped. " +
                "This should only be used for debugging npm service issues.",
                DisablePackageValidationKey);
        }

try
        {
            MirrorSkillFiles(repoRoot, selectedSkillDirectories, preExisting);
        }
        catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
        {
            logger.LogWarning(ex, "Failed to mirror Playwright CLI skill files to some locations.");
            return (PlaywrightInstallStatus.InstalledWithWarnings, AgentCommandStrings.PlaywrightCliInstaller_InstalledWithMirrorWarnings);
        }

if (socket is null)
        {
            logger.LogDebug("Connecting to auxiliary backchannel at {SocketPath}", socketPath);

            socket = new Socket(AddressFamily.Unix, SocketType.Stream, ProtocolType.Unspecified);
            var endpoint = new UnixDomainSocketEndPoint(socketPath);
            await socket.ConnectAsync(endpoint, cancellationToken).ConfigureAwait(false);
        }

try
        {
            return await rpc.InvokeWithProfilingAsync<WaitForAppHostReadyResponse>(
                _profilingTelemetry,
                "auxiliary",
                "WaitForAppHostReadyAsync",
                [new WaitForAppHostReadyRequest()],
                cancellationToken).ConfigureAwait(false);
        }
        catch (RemoteMethodNotFoundException ex)
        {
            _logger.LogDebug(ex, "WaitForAppHostReadyAsync RPC method not available on the remote AppHost. The AppHost may be running an older version.");
            return null;
        }

try
        {
            snapshots = await rpc.InvokeStreamingWithProfilingAsync<ResourceSnapshot>(
                _profilingTelemetry,
                "auxiliary",
                "WatchResourceSnapshotsAsync",
                [],
                cancellationToken).ConfigureAwait(false);
        }
        catch (RemoteMethodNotFoundException ex)
        {
            _logger.LogDebug(ex, "WatchResourceSnapshotsAsync RPC method not available on the remote AppHost. The AppHost may be running an older version.");
            yield break;
        }

try
        {
            snapshots = await rpc.InvokeStreamingWithProfilingAsync<ResourceSnapshot>(
                _profilingTelemetry,
                "auxiliary",
                "WatchResourcesAsync",
                [request],
                cancellationToken).ConfigureAwait(false);
        }
        catch (RemoteMethodNotFoundException)
        {
            yield break;
        }

try
        {
            await rpc.InvokeWithProfilingAsync(
                profilingTelemetry,
                "apphost",
                "NotifyAppHostReadyAsync",
                [],
                cancellationToken);
        }
        catch (RemoteMethodNotFoundException ex)
        {
            logger.LogDebug(ex, "NotifyAppHostReadyAsync RPC method not available on the remote AppHost. The AppHost may be running an older version.");
        }

try
        {
            await foreach (var changed in WatchForChangesAsync(fileProvider, watchPattern, cancellationToken))
            {
                await ProcessDirectoryChangesAsync(cancellationToken).ConfigureAwait(false);
            }
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Expected during shutdown
        }

try
        {
            var response = await rpc.InvokeWithCancellationAsync<IAsyncEnumerable<T>>(methodName, arguments, cancellationToken).ConfigureAwait(false);
            activity.AddJsonRpcResponseReceivedEvent();

            return EnumerateWithProfiling(response, activity, spanLifetime, cancellationToken);
        }
        catch (Exception ex)
        {
            activity.SetError(ex);
            activity.Dispose();
            throw;
        }

if (!IsVersionedLayoutValid(activeVersionDir))
        {
            logger.LogDebug("Versioned layout {Path} not valid or missing; extracting fresh.", activeVersionDir);
            if (!await ExtractVersionedLayoutAsync(versionsRoot, versionId, activeVersionDir, cancellationToken).ConfigureAwait(false))
            {
                return BundleExtractResult.ExtractionFailed;
            }
        }
        else
        {
            logger.LogDebug("Reusing existing versioned layout at {Path}.", activeVersionDir);
        }

if (layoutDiscovery.DiscoverLayout() is null)
        {
            logger.LogError("Post-flip layout validation failed; attempting rollback.");
            if (!TryRestoreLinks(destinationPath, priorTargets))
            {
                logger.LogError("Rollback of bundle links failed; layout is in an inconsistent state.");
            }
            return BundleExtractResult.ExtractionFailed;
        }

foreach (var candidate in certificatesWithSubjectName.OfType<X509Certificate2>())
        {
            if (foundCertificate is null && AreCertificatesEqual(candidate, certificate))
            {
                foundCertificate = candidate;
            }
            else
            {
                certificatesToDispose.Add(candidate);
            }
        }

try
        {
            certificateManager.CleanupHttpsCertificates();
            return new CertificateCleanResult { Success = true };
        }
        catch (CryptographicException ex) when (ex.HResult == UserCancelledHResult || ex.HResult == UserCancelledErrorCode)
        {
            return new CertificateCleanResult { Success = false, WasCancelled = true, ErrorMessage = ex.Message };
        }
        catch (Exception ex)
        {
            return new CertificateCleanResult { Success = false, ErrorMessage = ex.Message };
        }

foreach (var channel in channels)
        {
            foreach (var package in distinctPackageIds)
            {
                var packages = await channel.GetPackageVersionsAsync(package.Package.Id, workingDirectory, cancellationToken);
                versions.AddRange(packages.Select(p => (FriendlyName: package.FriendlyName, Package: p, Channel: channel)));
            }
        }

foreach (var update in configUpdates)
        {
            try
            {
                await update.ApplyAsync(cancellationToken);
                InteractionService.DisplayMessage(KnownEmojis.Wrench, update.Description);
            }
            catch (InvalidOperationException ex)
            {
                InteractionService.DisplayError(ex.Message);
            }
        }

if (result.Status is AspireSkillsInstallStatus.Installed)
        {
            bundle = result.Bundle ?? throw new InvalidOperationException("Aspire skills installer returned an installed result without a bundle.");
            skills.AddRange(bundle.GetSkillDefinitions().Where(static skill => !IsCliDefinedSkillName(skill.Name)));
        }
        else
        {
            // Preserve the install failure so the caller can surface it only when the user
            // passed an explicit --skills value that names a bundle-only skill. Happy-path
            // (interactive prompt with the embedded fallback) stays silent.
            failureMessage = result.Message;
        }

if (skill.SourceKind is SkillSourceKind.AspireSkillsBundle)
        {
            if (aspireSkillsBundle is null)
            {
                throw new InvalidOperationException($"Aspire skills bundle was not resolved for skill '{skill.Name}'.");
            }

            return await aspireSkillsBundle.GetSkillFilesAsync(skill, cancellationToken);
        }

if (!_resourceToolRefreshService.TryGetResourceToolMap(out var resourceToolMap))
        {
            bool changed;
            (resourceToolMap, changed) = await _resourceToolRefreshService.RefreshResourceToolMapAsync(cancellationToken);
            if (changed)
            {
                await _resourceToolRefreshService.SendToolsListChangedNotificationAsync(cancellationToken).ConfigureAwait(false);
            }
            toolsRefreshed = true;
        }

try
        {
            searchResult = await projectLocator.UseOrFindAppHostProjectFileAsync(
                passedAppHostProjectFile,
                multipleAppHostBehavior,
                createSettingsFile: false,
                cancellationToken);
        }
        catch (ProjectLocatorException ex)
        {
            return BaseCommand.HandleProjectLocatorException(ex, interactionService, telemetry);
        }

try
        {
            launchResult = await interactionService.ShowDynamicStatusAsync(
                RunCommandStrings.StartingAppHostInBackground,
                updateStatus => LaunchAndWaitForBackchannelAsync(executablePath, childArgs, expectedHash, legacyHashes, TimeSpan.FromSeconds(timeoutSeconds), updateStatus, cancellationToken));
        }
        catch (OperationCanceledException)
        {
            return CommandResult.Cancelled(CliExitCodes.Success);
        }

if (existingSockets.Length > 0)
        {
            logger.LogDebug("Found {Count} running instance(s) for this AppHost, stopping them first.", existingSockets.Length);
            var manager = new RunningInstanceManager(logger, interactionService, timeProvider);
            var stopTasks = existingSockets.Select(socket =>
                manager.StopRunningInstanceAsync(socket, cancellationToken));
            await Task.WhenAll(stopTasks).ConfigureAwait(false);
        }

if (IsSuccessfulDetachedEarlyExit(exitCode))
        {
            logger.LogInformation("Child CLI process exited successfully before AppHost readiness was observed.");
        }
        else
        {
            waitForBackchannelActivity.SetError($"Child CLI exited with code {exitCode}.");
            logger.LogWarning("Child CLI process exited with code {ExitCode}", exitCode);
        }

if (UpdateNotificationsEnabled && !IsJsonFormatRequested(parseResult) && features.IsFeatureEnabled(KnownFeatures.UpdateNotificationsEnabled, true))
            {
                try
                {
                    updateNotifier.NotifyIfUpdateAvailable();
                }
                catch
                {
                    // Ignore any errors during update check to avoid impacting the main command
                }
            }

foreach (var subdirectory in directory.EnumerateDirectories())
            {
                try
                {
                    subdirectory.Delete(recursive: true);
                }
                catch (Exception ex) when (ex is IOException or UnauthorizedAccessException or System.Security.SecurityException)
                {
                    // Continue deleting other directories even if some fail
                }
            }
